import{_ as l}from"./plugin-vue_export-helper-c27b6911.js";import{o as e,c as n,f as a,a as i,b as t}from"./app-9f08e215.js";const r="/assets/img/psychology_and_life_2/image-20260616184640343.png",s="/assets/img/psychology_and_life_2/image-20260616195633084.png",p="/assets/img/psychology_and_life_2/image-20260616195903732.png",h="/assets/img/psychology_and_life_2/image-20260617103722349.png",o="/assets/img/psychology_and_life_2/image-20260617111213318.png",d="/assets/img/psychology_and_life_2/image-20260617112459579.png",c="/assets/img/psychology_and_life_2/image-20260617231417764.png",g="/assets/img/psychology_and_life_2/image-20260618155648622.png",u={},f=a('<h2 id="感觉和知觉" tabindex="-1"><a class="header-anchor" href="#感觉和知觉" aria-hidden="true">#</a> 感觉和知觉</h2><p>术语：</p><ul><li>知觉：理解环境中客体和事件的所有过程--感觉、理解、识别和标记它们，以及准备对他们做出反应。 <ul><li>感觉组织：如眼睛中的神经细胞向大脑皮层细胞传递信息，大脑皮层细胞从这一输入提取初步的特征。</li><li>知觉组织：大脑整合来自感官的证据以及对世界的已有知识，形成对外部刺激的内部表征。</li><li>识别组织：就视觉而言，知觉的上一阶段是回答看起来想什么，这一阶段变成了辨认这个物体是什么，和识别这个物体的功能是什么。</li></ul></li></ul><hr><h3 id="心理物理学" tabindex="-1"><a class="header-anchor" href="#心理物理学" aria-hidden="true">#</a> 心理物理学</h3><p>测量物理刺激强度（以物理单位测量）和感觉体验大小（以心理单位测量）之间的方法。</p><ul><li>绝对阈限：产生感觉体验所需的最小物理刺激量。操作性定义：有一半次数能够觉察到感觉信号的刺激水平。</li><li>感觉适应：对持续的刺激输入反应逐渐减小的现象。</li><li>反应偏差：由一些阈刺激的感觉特性无关的因素所引起的系统性趋势。</li><li>信号检测论：不严格地关注感觉过程，而是强调刺激事件出现与否的判断过程。</li></ul><p>比如在房间里听轻柔的声音。每一次测试时刺激的强度都不同，每一次测试中观察者都回答他们是否意识到刺激。</p><figure><img src="'+r+'" alt="image-20260616184640343" tabindex="0" loading="lazy"><figcaption>image-20260616184640343</figcaption></figure><p>信号检测论区分出感觉觉察的两个独立过程，最初的感觉过程，反应观察者对刺激强度的感受性；随后的决策过程，反应观察者的反应偏差。通过测量 TP,TN,FP,FN，使用数学方法可以大致解析出感觉过程和反应偏差。</p><ul><li>差别阈限（最小可觉差）：你能够识别出两个刺激之间的最小物理量；操作性定义：有一半次数觉察出差异的刺激值</li></ul><div class="hint-container info"><p class="hint-container-title">相关信息</p><p>假设你公司想要生产一种可乐，口味比现有的可乐稍微甜一点，但是（为了省钱）公司想尽可能少地在可乐中加糖。</p><p>你可以每次给观察者两种可乐，一个是标准可乐，一个稍微甜一点。观察者对每一对可乐都回答相同或者不同。</p></div><ul><li>韦伯定律：刺激之间的 JND 与标准刺激强度的 <strong>比值</strong> 是恒定的。对于每一种刺激，这个比率都有一个特定的值。 <strong>但当刺激强度极高时，韦伯定律不适用。</strong></li></ul><figure><img src="'+s+'" alt="image-20260616195633084" tabindex="0" loading="lazy"><figcaption>image-20260616195633084</figcaption></figure><figure><img src="'+p+'" alt="image-20260616195903732" tabindex="0" loading="lazy"><figcaption>image-20260616195903732</figcaption></figure><hr><h4 id="物理事件到心理事件" tabindex="-1"><a class="header-anchor" href="#物理事件到心理事件" aria-hidden="true">#</a> 物理事件到心理事件</h4><ul><li>换能：从一种物理能量形式（如光）到另一种形式（如神经冲动）的转换</li><li>感受器：把感觉信号的物理形式转换为能够被神经系统加工的细胞信号。</li></ul><hr><h3 id="视觉系统" tabindex="-1"><a class="header-anchor" href="#视觉系统" aria-hidden="true">#</a> 视觉系统</h3><p>高度简化且经过标准化的示意图</p><figure><img src="'+h+'" alt="视网膜神经通路" tabindex="0" loading="lazy"><figcaption>视网膜神经通路</figcaption></figure><ul><li>杆体细胞在近乎黑暗时刻拥有最佳功能</li><li>锥体细胞特别应对明亮而充满色彩的白天</li><li>双极细胞：一种神经细胞，它整合感受器的神经冲动，并传递到神经节细胞。每一个神经细胞豆浆整合一个或者多个双极细胞的冲动，形成单一的发放频率。</li><li>水平细胞：链接感受器</li><li>无长突细胞：负责双极细胞之间和神经节细胞之间的链接。</li></ul><p>暗适应过程是由于在黑暗中停留后，杆体细胞比锥体细胞变得更敏感。</p><hr><ul><li>大脑的加工</li></ul><p>大多数视觉信息的最后目的是大脑枕叶上被称为初级视皮层的区域。然而大多数信息在离开视网膜之后，到达视皮层之前，还要经过其他的脑区。</p><figure><img src="'+o+'" alt="image-20260617111213318" height="400" tabindex="0" loading="lazy"><figcaption>image-20260617111213318</figcaption></figure><p>两束神经纤维包括来自两只眼睛的轴突，重新命名为视束。视束向大脑中的两个神经细胞群传递信息，研究证明，视觉分析可以分为两个通路，客体识别（看起来像什么）和位置识别（客体的位置）</p><ul><li>感受野：细胞接受刺激的区域。</li></ul><div class="hint-container info"><p class="hint-container-title">相关信息</p><figure><img src="'+d+'" alt="image-20260617112459579" tabindex="0" loading="lazy"><figcaption>image-20260617112459579</figcaption></figure><p>视觉通路上细胞的感受野就是接受刺激的视野区域。视网膜上神经节细胞的感受野是同心圆(A,B)；这些视觉皮层上最简单的细胞沿一定朝向被拉伸了(C、D、E、F)。在这两种情况下，对感受野起反应的细胞，对标有“+”号区域的光产生兴奋，对标有“-”号区域的光产生抑制。此外，最令细胞兴奋的刺激，在光导致细胞兴奋的区域（标+号）是光亮的，而在光导致细胞抑制的区域（标-号）是黑暗的。</p></div><p>将注意力从手移向另一类别的一个客体时，你的大脑的一个特定区域就会一开一闭。一些脑区对有生命的刺激更活跃（如人脸、身体、昆虫）而其他脑区则对无生命的刺激更活跃（如工具、武器、衣服）</p><p><strong>疑问：</strong> 脑区在出生时就有着特殊的功能，或这些功能是生活经验的产物？</p><p><strong>疑问：</strong> 对有生命的客体和无生命的客体类别做出的不同反应。每一个类别中都有视觉上有差异的客体（如武器和椅子），为什么这一点很重要？</p><p><strong>疑问：</strong> fMRI 的测试具体如何进行的。</p><p><strong>疑问：</strong> 视觉信号经过了哪些脑区到达视觉皮层，视觉皮层之后信号又被传递到什么脑区。有研究表明思考时候视觉信号的传递路径吗？</p><hr><h3 id="颜色视觉" tabindex="-1"><a class="header-anchor" href="#颜色视觉" aria-hidden="true">#</a> 颜色视觉</h3><ol><li>正常人的眼睛具有三种类型的颜色感受器（三种锥体细胞，感受不同光波）</li><li>视网膜的神经节细胞综合三种锥体细胞的输出，一些神经节细胞接受来自红光的兴奋性输入和来自绿光的抑制性输入。</li></ol><ul><li>opponent-process theory：颜色产证互补色的视觉后巷，是因为系统中的一个成分疲劳了（由于过度刺激），因此增加了他的 opponent-process 成分的相对作用。红对绿，黄对蓝。</li></ul><hr><h3 id="听觉" tabindex="-1"><a class="header-anchor" href="#听觉" aria-hidden="true">#</a> 听觉</h3><p>频率和振幅形成了声音的三个心理维度：音高、响度和音色。</p><ul><li>音高：由频率决定；频率和音高（心理效果）之间并不是线性关系。参考之前的差别阈限。</li><li>响度：由振幅决定；声压（产生响度体验的振幅大小的指标）通过分贝来测量。</li><li>音色：复杂声波的成分；多种频率和振幅组成的混合波。</li></ul><div class="hint-container info"><p class="hint-container-title">相关信息</p><figure><img src="'+c+'" alt="image-20260617231417764" height="400" tabindex="0" loading="lazy"><figcaption>image-20260617231417764</figcaption></figure><p>声波通过外耳或耳廓，经外耳道传入，引起鼓膜振动。这个振动激活了内耳中的小骨——锤骨、砧骨和镫骨。它们的机械振动经过卵圆窗到达耳蜗，并使管道里的液体振动。当液体流动时，耳蜗中盘旋的基底膜内层上微小的 <strong>毛细胞</strong> 弯曲，刺激附着在其上的神经末梢。物理刺激就此被转换为神经能量，并且通过听神经传送到大脑。</p></div><p>与视觉系统的神经交叉一样，来自一只耳朵的刺激传递到两侧的大脑。听觉信号到达位于大脑半球的颞叶听皮层之前要经过一系列的神经核团。</p><p>音高心理感觉：</p><ul><li>频率理论：基底膜震动的频率来解释音高。基底膜的震动将引起相同的频率的神经放电，神经放电的频率就是音高的神经代码。（更好地解释低于 5000 赫兹的声音编码。）</li><li>地点理论：不同的频率在基底膜的不同位置上产生它们最大的运动。（更好地解释 1000 赫兹以上的音高）</li></ul><p>声音定位：</p><ul><li>相对时间：神经元比较进入每一只耳朵的声音的时间差。听觉系统的神经元会在两耳之间产生特定时间延迟时特异性地放电。</li><li>相对强度：先到达耳朵的声音强度会稍微高一点。</li><li>个人观点：声音与其他知觉在脑海中构建的画面，最终判断了声音的来源。</li></ul><hr><h3 id="嗅觉" tabindex="-1"><a class="header-anchor" href="#嗅觉" aria-hidden="true">#</a> 嗅觉</h3><p>气味刺激产生嗅觉的过程开始于化学物质流入嗅觉神经元的离子通道，它们将信息传递给大脑中的嗅球。</p><figure><img src="'+g+'" alt="image-20260618155648622" height="400" tabindex="0" loading="lazy"><figcaption>image-20260618155648622</figcaption></figure><ul><li>信息素：一种化学物质，在特定物种内用来传递性接纳、危险、领地分界和食物源等信息。</li></ul><h3 id="味觉" tabindex="-1"><a class="header-anchor" href="#味觉" aria-hidden="true">#</a> 味觉</h3><p>食物的味道很多时候依靠的是嗅觉而非味觉。</p><ul><li>味蕾：味觉感受细胞，单个细胞对于基本味道（酸甜苦辣鲜）中的某一种反应最为强烈。</li></ul><h3 id="触觉和肤觉" tabindex="-1"><a class="header-anchor" href="#触觉和肤觉" aria-hidden="true">#</a> 触觉和肤觉</h3><p>皮肤对压力的敏感性在身体不同部位的差异非常大。</p><p>身体中并没有类似温度计的感受器，而是大脑整合了来自冷传感纤维和暖传感纤维的分离信号。</p><h3 id="前庭觉和动觉" tabindex="-1"><a class="header-anchor" href="#前庭觉和动觉" aria-hidden="true">#</a> 前庭觉和动觉</h3><ul><li>前庭觉：你的身体（特别是头部）是如何根据重力作用确定方向的。</li></ul><p>当快速转动头部时，内耳中的液体流动并压迫纤毛，从而导致纤毛弯曲。球囊和椭圆囊告诉你关于在直线上加速或减速的信息。三个被称为半规管的导管是相互垂直的，它们能够告诉你关于在任何方向上运动的信息。</p><ul><li>动觉：关节中的感受器，以及位于肌肉和肌腱中的感受器。位于关节中的感受器对伴随不同肢体位置和关节运动的压力变化起反应。肌肉和肌腱中的感受器对伴随肌肉收缩和舒张是的张力变化起反应。</li></ul><h3 id="痛觉" tabindex="-1"><a class="header-anchor" href="#痛觉" aria-hidden="true">#</a> 痛觉</h3><ul><li>痛觉是身体队有害刺激的反应，即那些强度足够导致组织损伤或具有这种威胁性的刺激。</li></ul><p>外周神经纤维通过两条路径将痛觉信号传递到中枢神经系统：神经纤维外部包囊髓磷脂的快速传到路径，以及神经纤维外部没有包囊髓磷脂的缓慢的、小的传导路径。</p><p>痛觉神经起始于脊髓，然后转送到丘脑，最后到达大脑皮层。</p><p>内啡呔会影响你的痛觉体验。</p><ul><li>门控理论</li></ul><p>一种解释疼痛调节的理论；脊髓中的细胞像神经闸门一样切断和阻止一些痛觉信号进入大脑，而允许其他信号进入。</p><hr><h3 id="知觉的组织过程" tabindex="-1"><a class="header-anchor" href="#知觉的组织过程" aria-hidden="true">#</a> 知觉的组织过程</h3><h4 id="注意过程" tabindex="-1"><a class="header-anchor" href="#注意过程" aria-hidden="true">#</a> 注意过程</h4><ul><li><p>目标指向选择：你对将要注意的客体做出的选择。</p></li><li><p>刺激驱动捕获：发生在刺激的特征（环境中的客体）自动抓住你的注意之时，它不依赖于知觉者当时的目标。</p></li></ul><h4 id="知觉组织原则" tabindex="-1"><a class="header-anchor" href="#知觉组织原则" aria-hidden="true">#</a> 知觉组织原则</h4><p>直觉组织的第一步是将场景的一部分解读为突触背景的图片。</p><p>知觉组织的原则在格式塔心理学中得以深入研究。它主张心理现象只有被视为有组织和结构的整体时才可以得到理解，而不是分解成原始的直觉元素。</p><ul><li>接近律。人们将最接近的元素组织在一起。</li><li>相似律。人们将最相似的元素组织在一起。</li><li>连续律。即便线条被截断或覆盖了一部分，人们也会将其知觉为连续的。</li><li>闭合律。人们倾向于填补小的空隙而将客体知觉为一个整体。</li><li>共同命运体。人们倾向于将看起来朝向相同的方向运动的客体组织起来。</li></ul><p>许多直觉过程都需要以恰当的方式将世界的碎片整合在一起。</p><h4 id="空间和时间上的整合" tabindex="-1"><a class="header-anchor" href="#空间和时间上的整合" aria-hidden="true">#</a> 空间和时间上的整合</h4><p>视觉系统无需费力就能创建一个关于环境的实时整合图形。研究表明，你每一次注视环境的视觉记忆并没有保留精确的细节。（回想一下窗外看到的画面是什么？想象中的肯定会比实际看到的要多）</p><p>人们在很多情况下无法注意到从一个场景到下一个场景的变换。比较戏剧性的是“变化盲视”。</p><h4 id="运动直觉" tabindex="-1"><a class="header-anchor" href="#运动直觉" aria-hidden="true">#</a> 运动直觉</h4>',85),_=i("p",null,[i("span",{class:"katex"},[i("span",{class:"katex-mathml"},[i("math",{xmlns:"http://www.w3.org/1998/Math/MathML"},[i("semantics",null,[i("mrow",null,[i("mi",null,"ϕ")]),i("annotation",{encoding:"application/x-tex"},"\\phi")])])]),i("span",{class:"katex-html","aria-hidden":"true"},[i("span",{class:"base"},[i("span",{class:"strut",style:{height:"0.8889em","vertical-align":"-0.1944em"}}),i("span",{class:"mord mathnormal"},"ϕ")])])]),t(" 现象属于视觉错觉中的运动错觉，是似动的一种典型表现。如电影不同帧之间的切换，视觉系统会按照正常的生物学运动路径进行填充。")],-1),m=a('<h4 id="深度知觉" tabindex="-1"><a class="header-anchor" href="#深度知觉" aria-hidden="true">#</a> 深度知觉</h4><p>深度=你与客体的距离</p><ul><li>双眼线索和运动线索：双眼深度信息的两个来源是视网膜像差（双眼的图像在水平方向上的位移）和视轴辐合（两只眼睛向内侧转动时，眼部肌肉的信息）</li></ul><p>如果视网膜上的对应图像差别足够小，视觉系统能把它们融合为某个深度上对单个体的知觉。</p><ul><li><p>运动视差：环境中物体的相对距离决定了它们在视网膜影像上相对运动的大小和方向。</p></li><li><p>单眼深度线索：通过相对大小、线条透视和质地梯度（密度）判断深度。</p></li><li><p>庞佐错觉：汇聚的线条增加了深度的维度，因此距离线索导致下面的线条看起来比上边的线条更长，即使它们事实上具有相同的长度。</p></li></ul><h4 id="知觉恒常性" tabindex="-1"><a class="header-anchor" href="#知觉恒常性" aria-hidden="true">#</a> 知觉恒常性</h4><p>一般来说，尽管你的感受器接收的刺激在改变，但你所看到的世界是不变的、恒常的、稳定的。这种现象称为直觉恒常性。</p><p>知觉的重要任务是在视网膜成像发生变化的条件下去发现环境中恒定的性质。</p><ul><li>大小恒常性：在视网膜成像大小变化的情况下感知客体真实大小的能力。（通常动过深度、经验判断）</li><li>形状恒常性：视网膜成像的形状实际上不同于客体本身的形状时，你仍然能够正确地感知客体的形状。</li><li>亮度恒常性：在不同的照明条件下，将物体的白度、灰度和黑度知觉为恒定的倾向。</li></ul>',9),x=[f,_,m];function y(b,v){return e(),n("div",null,x)}const k=l(u,[["render",y],["__file","笔记psychology_and_life_2.html.vue"]]);export{k as default};
